317		-- Environment
318		-- ==========================================================================
319		function is_simulation return boolean is
320			variable ret : boolean;
321		begin
322			ret := false;
323			-- WORKAROUND: for Xilinx ISE
324			--	Version:	all versions with enabled 'use_new_parser' option
325			--	Issue:		Is_X('X') does not evaluate to FALSE in synthesis
326			--	Solution:	Use '--synthesis translate_on/off' pragmas
327			--synthesis translate_off
328			if Is_X('X') then ret := true; end if;
329			--synthesis translate_on
330			return	ret;
331		end function;
