474	
475		-- Divisions: div_*
476		-- ===========================================================================
477		-- integer division; always round-up
478		function div_ceil(a : natural; b : positive) return natural is	-- calculates: ceil(a / b)
479		begin
480			return (a + (b - 1)) / b;
481		end function;
482	
483		-- Power functions: *_pow2
484		-- ==========================================================================
485		-- return TRUE, if input is a power of 2
486		function is_pow2(int : natural) return boolean is
487		begin
488			return ceil_pow2(int) = int;
489		end function;
490	
491		-- round to next power of 2
492		function ceil_pow2(int : natural) return positive is
493		begin
494			return 2 ** log2ceil(int);
495		end function;
496	
497		-- round to previous power of 2
498		function floor_pow2(int : natural) return natural is
499			variable temp : unsigned(30 downto 0);
500		begin
501			temp	:= to_unsigned(int, 31);
502			for i in temp'range loop
503				if (temp(i) = '1') then
504					return 2 ** i;
505				end if;
506			end loop;
507			return 0;
508		end function;
509	
510		-- Logarithms: log*ceil*
511		-- ==========================================================================
512		-- return log2; always rounded up
513		function log2ceil(arg : positive) return natural is
514			variable tmp : positive;
515			variable log : natural;
516		begin
517			if arg = 1 then	return 0; end if;
518			tmp := 1;
519			log := 0;
520			while arg > tmp loop
521				tmp := tmp * 2;
522				log := log + 1;
523			end loop;
524			return log;
525		end function;
526	
527		-- return log2; always rounded up; the return value is >= 1
528		function log2ceilnz(arg : positive) return positive is
529		begin
530			return imax(1, log2ceil(arg));
531		end function;
532	
533		-- return log10; always rounded up
534		function log10ceil(arg : positive) return natural is
535			variable tmp : positive;
536			variable log : natural;
537		begin
