1022		-- Swap sub vectors in vector
1023		-- ==========================================================================
1024		function swap(slv : std_logic_vector; Size : positive) return std_logic_vector is
1025			constant SegmentCount	: natural													:= slv'length / Size;
1026			variable FromH				: natural;
1027			variable FromL				: natural;
1028			variable ToH					: natural;
1029			variable ToL					: natural;
1030			variable Result : std_logic_vector(slv'length - 1 downto 0);
1031		begin
1032			for i in 0 to SegmentCount - 1 loop
1033				FromH		:= ((i + 1) * Size) - 1;
1034				FromL		:= i * Size;
1035				ToH			:= ((SegmentCount - i) * Size) - 1;
1036				ToL			:= (SegmentCount - i - 1) * Size;
1037				Result(ToH downto ToL)	:= slv(FromH downto FromL);
1038			end loop;
1039			return Result;
1040		end function;
