1043		-- Swap the bits in a chunk
1044		-- ==========================================================================
1045		function bit_swap(slv : std_logic_vector; Chunksize : positive) return std_logic_vector is
1046			constant SegmentCount	: natural	:= slv'length / Chunksize;
1047			variable FromH				: natural;
1048			variable FromL				: natural;
1049			variable Result			: std_logic_vector(slv'length - 1 downto 0);
1050		begin
1051			for i in 0 to SegmentCount - 1 loop
1052				FromH		:= ((i + 1) * Chunksize) - 1;
1053				FromL		:= i * Chunksize;
1054				Result(FromH downto FromL)	:= reverse(slv(FromH downto FromL));
1055			end loop;
1056			return Result;
1057		end function;
