1094		-- One-Hot-Code to Binary-Code
1095	  function onehot2bin(onehot : std_logic_vector; empty_val : integer := -1) return unsigned is
1096			variable res : unsigned(log2ceilnz(imax(onehot'high, empty_val)+1)-1 downto 0);
1097			variable chk : natural;
1098		begin
1099			-- Note: empty_val = 0 takes the regular path to reduce on synthesized hardware
1100			if empty_val > 0 and onehot = (onehot'range => '0') then
1101				res := to_unsigned(empty_val, res'length);
1102			else
1103				res := (others => '0');
1104				chk := 0;
1105				for i in onehot'range loop
1106					if onehot(i) = '1' then
1107						res := res or to_unsigned(i, res'length);
1108						chk := chk + 1;
1109					end if;
1110				end loop;
1111	
1112				if SIMULATION and chk /= 1 and (chk > 1 or empty_val < 0) then
1113					report "Broken 1-Hot-Code with "&integer'image(chk)&" bits set."
1114						severity warning;
1115					res := (others => 'X'); -- computed result is implementation-dependant
1116				end if;
1117			end if;
1118			return	res;
1119		end function;
