1122		function gray2bin(gray_val : std_logic_vector) return std_logic_vector is
1123			variable tmp : std_logic_vector(gray_val'length downto 0);
1124			variable res : std_logic_vector(gray_val'range);
1125		begin
1126			tmp := '0' & gray_val;
1127	    for i in tmp'left-1 downto 0 loop
1128	      tmp(i) := tmp(i+1) xor tmp(i);
1129	    end loop;
1130	    res := tmp(tmp'left-1 downto 0);
1131			return  res;
1132		end function;
