1203	  function mssb(arg : bit_vector) return bit_vector is
1204	  begin
1205	    return  reverse(lssb(reverse(arg)));
1206	  end function;
1207	
1208		-- Index of lssb
1209		function lssb_idx(arg : std_logic_vector) return integer is
1210		begin
1211			return  to_integer(onehot2bin(lssb(arg)));
1212		end function;
1213	
1214		function lssb_idx(arg : bit_vector) return integer is
1215	    variable  slv : std_logic_vector(arg'range);
1216		begin
1217	    slv := to_stdlogicvector(arg);
1218			return  lssb_idx(slv);
1219		end function;
1220	
1221		-- Index of mssb
1222		function mssb_idx(arg : std_logic_vector) return integer is
1223		begin
1224			return to_integer(onehot2bin(mssb(arg)));
1225		end function;
1226	
1227		function mssb_idx(arg : bit_vector) return integer is
1228	    variable  slv : std_logic_vector(arg'range);
1229		begin
1230	    slv := to_stdlogicvector(arg);
1231			return mssb_idx(slv);
1232		end function;
1233	
1234		-- scale a value into a given range
1235		function scale(Value : integer; Minimum : integer; Maximum : integer; RoundingStyle : T_ROUNDING_STYLE := ROUND_TO_NEAREST) return integer is
1236		begin
1237			return scale(real(Value), Minimum, Maximum, RoundingStyle);
1238		end function;
1239	
1240		function scale(Value : REAL; Minimum : integer; Maximum : integer; RoundingStyle : T_ROUNDING_STYLE := ROUND_TO_NEAREST) return integer is
1241			variable Result	: REAL;
1242		begin
1243			if Maximum < Minimum then
1244				return integer'low;
1245			else
1246				Result	:= real(Value) * ((real(Maximum) + 0.5) - (real(Minimum) - 0.5)) + (real(Minimum) - 0.5);
1247				case RoundingStyle is
1248					when ROUND_TO_NEAREST =>	return integer(round(Result));
1249					when ROUND_TO_ZERO =>			report "scale: unsupported RoundingStyle." severity FAILURE;
1250					when ROUND_TO_INF =>			report "scale: unsupported RoundingStyle." severity FAILURE;
1251					when ROUND_UP =>					return integer(ceil(Result));
1252					when ROUND_DOWN =>				return integer(floor(Result));
1253					when others =>						report "scale: unsupported RoundingStyle." severity FAILURE;
1254				end case;
1255				return integer(Result);
1256			end if;
1257		end function;
1258	
1259		function scale(Value : REAL; Minimum : REAL; Maximum : REAL) return REAL is
1260		begin
1261			if Maximum < Minimum then
1262				return REAL'low;
1263			else
1264				return Value * (Maximum - Minimum) + Minimum;
1265			end if;
1266		end function;
1267	
1268		function resize(vec : bit_vector; length : natural; fill : bit := '0') return bit_vector is
1269	    constant  high2b : natural := vec'low+length-1;
1270			constant  highcp : natural := imin(vec'high, high2b);
1271	    variable  res_up : bit_vector(vec'low to high2b);
1272	    variable  res_dn : bit_vector(high2b downto vec'low);
1273		begin
1274	    if vec'ascending then
1275	      res_up := (others => fill);
1276	      res_up(vec'low to highcp) := vec(vec'low to highcp);
1277	      return  res_up;
1278	    else
1279	      res_dn := (others => fill);
1280	      res_dn(highcp downto vec'low) := vec(highcp downto vec'low);
1281	      return  res_dn;
1282			end if;
1283		end function;
1284	
1285		function resize(vec : std_logic_vector; length : natural; fill : std_logic := '0') return std_logic_vector is
1286	    constant  high2b : natural := vec'low+length-1;
1287			constant  highcp : natural := imin(vec'high, high2b);
1288	    variable  res_up : std_logic_vector(vec'low to high2b);
1289	    variable  res_dn : std_logic_vector(high2b downto vec'low);
1290		begin
1291	    if vec'ascending then
1292	      res_up := (others => fill);
1293	      res_up(vec'low to highcp) := vec(vec'low to highcp);
1294	      return  res_up;
1295	    else
1296	      res_dn := (others => fill);
1297	      res_dn(highcp downto vec'low) := vec(highcp downto vec'low);
1298	      return  res_dn;
1299			end if;
1300		end function;
1301	
1302		-- Move vector boundaries
1303		-- ==========================================================================
1304	  function move(vec : std_logic_vector; ofs : integer) return std_logic_vector is
1305	    variable res_up : std_logic_vector(vec'low +ofs to     vec'high+ofs);
1306	    variable res_dn : std_logic_vector(vec'high+ofs downto vec'low +ofs);
1307	  begin
1308	    if vec'ascending then
1309	      res_up := vec;
1310	      return  res_up;
1311	    else
1312	      res_dn := vec;
1313	      return  res_dn;
1314	    end if;
1315	  end function;
1316	
1317		function movez(vec : std_logic_vector) return std_logic_vector is
1318	  begin
1319	    return  move(vec, -vec'low);
1320	  end function;
1321	
1322	  function ascend(vec : std_logic_vector)	return std_logic_vector is
1323			variable  res : std_logic_vector(vec'low to vec'high);
1324		begin
1325			res := vec;
1326			return  res;
1327		end function;
1328	
1329	  function descend(vec : std_logic_vector)	return std_logic_vector is
1330			variable  res : std_logic_vector(vec'high downto vec'low);
1331		begin
1332			res := vec;
1333			return  res;
1334		end function;
1335	end package body;
1336

